import{_ as e,o as n,c as r,a3 as i}from"./chunks/framework.oxq6d-og.js";const k=JSON.parse('{"title":"Çökme ve hata ayıklama","description":"","frontmatter":{},"headers":[],"relativePath":"nthread/failure-modes.md","filePath":"nthread/failure-modes.md"}'),l={name:"nthread/failure-modes.md"};function d(o,a,s,t,m,u){return n(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="cokme-ve-hata-ayıklama" tabindex="-1">Çökme ve hata ayıklama <a class="header-anchor" href="#cokme-ve-hata-ayıklama" aria-label="Permalink to &quot;Çökme ve hata ayıklama&quot;">​</a></h1><p>Süreçler arası context ve stack düzenleme hataları çoğu zaman host&#39;ta değil, hedef süreçte erişim ihlali olarak görünür. Aşağıdaki liste, NThread tasarımının doğrudan ele aldığı veya hâlâ kullanıcıdan doğru seçim beklediği riskleri açıklar.</p><h2 id="stack-donus-zincirinin-ezilmesi" tabindex="-1">Stack dönüş zincirinin ezilmesi <a class="header-anchor" href="#stack-donus-zincirinin-ezilmesi" aria-label="Permalink to &quot;Stack dönüş zincirinin ezilmesi&quot;">​</a></h2><p>Thread serbest bırakılırken özgün <code>RIP</code>/<code>RSP</code> geri yüklenir. Eğer geçici dönüş zinciri özgün stack pointer&#39;a fazla yakınsa, hedefin normal yürütmesi daha sonra bu alana inebilir ve eski bir stub adresini dönüş adresi sanabilir. Sonuç yanlış adrese <code>ret</code> ve çökmedir.</p><p>Bu yüzden NThread, yakalanan <code>RSP</code>&#39;nin altında <strong>bir tam sayfa (4096 byte)</strong> boşluk ayırır (<code>STACK_ADD = -4096</code>). Kaynak kodundaki not, 256 byte&#39;ın loader lock veya string dönüşümü gibi makul call chain&#39;lerde yetersiz kaldığını belirtir. Bu koruma riski azaltır; seçilen thread&#39;in stack sınırına olağandışı yakın olması gibi durumları tamamen ortadan kaldırmaz.</p><h2 id="abi-veya-imza-uyusmazlıgı" tabindex="-1">ABI veya imza uyuşmazlığı <a class="header-anchor" href="#abi-veya-imza-uyusmazlıgı" aria-label="Permalink to &quot;ABI veya imza uyuşmazlığı&quot;">​</a></h2><p>Yanlış argüman türü, yanlış argument sayısı, <code>f32</code>/<code>f64</code> değerini yanlış register&#39;dan geçirmek ya da dönüş türünü yanlış yorumlamak hedef fonksiyonun geçersiz pointer kullanmasına yol açabilir. Fonksiyon imzasını doğrulayın; özellikle struct-by-value, variadic fonksiyonlar ve özel calling convention&#39;lar için varsayım yapmayın.</p><h2 id="fonksiyon-geri-donmez-veya-thread-olur" tabindex="-1">Fonksiyon geri dönmez veya thread ölür <a class="header-anchor" href="#fonksiyon-geri-donmez-veya-thread-olur" aria-label="Permalink to &quot;Fonksiyon geri dönmez veya thread ölür&quot;">​</a></h2><p><code>ExitThread</code>, uzun süren bloklayıcı fonksiyonlar, exception ile kaçan akış veya sonsuz döngü, thread&#39;in spin stub&#39;a dönmesini engeller. Kütüphane bunu <code>CallTimeoutError</code> veya <code>CallThreadDiedError</code> olarak bildirir. Timeout sonrasında thread context&#39;ini körlemesine tekrar değiştirmeyin; hedefin hâlâ hayatta olup olmadığını ve thread&#39;in durumunu inceleyin.</p><h2 id="yanlıs-zamanda-suspend-etmek" tabindex="-1">Yanlış zamanda suspend etmek <a class="header-anchor" href="#yanlıs-zamanda-suspend-etmek" aria-label="Permalink to &quot;Yanlış zamanda suspend etmek&quot;">​</a></h2><p>Thread bir mutex&#39;i, loader lock&#39;u veya uygulamaya özgü kritik kaynağı tutarken askıya alınırsa diğer thread&#39;ler kilitlenebilir. Bu doğrudan access violation olmasa bile hedefi donmuş gibi gösterir. Kısa çağrılar seçin, timeout kullanın ve thread seçimini denetlenebilir hale getirin.</p><h2 id="stub-bulunamaması-veya-surum-varsayımları" tabindex="-1">Stub bulunamaması veya sürüm varsayımları <a class="header-anchor" href="#stub-bulunamaması-veya-surum-varsayımları" aria-label="Permalink to &quot;Stub bulunamaması veya sürüm varsayımları&quot;">​</a></h2><p>Başlatma, <code>ntdll</code>, <code>kernel32</code> ve <code>kernelbase</code> içinde gerekli küçük talimat dizilerini tarar. Tarama tamamlanmadan erişim yapılması yanıltıcı “stub yok” hatasına dönüşebildiği için async başlatma <code>whenStubsReady()</code> bekler. <code>NoSleepAddressError</code>, <code>NoPushretAddressError</code>, <code>NoJumpAddressError</code>, <code>NoRetAddressError</code> veya <code>NoAddRsp28RetAddressError</code> alınırsa önce hedef platformun Windows x64 olduğunu, modüllerin erişilebilirliğini ve tarama yaşam döngüsünü doğrulayın.</p><h2 id="inceleme-sırası" tabindex="-1">İnceleme sırası <a class="header-anchor" href="#inceleme-sırası" aria-label="Permalink to &quot;İnceleme sırası&quot;">​</a></h2><ol><li>Çağrılan adresin, process mimarisinin ve fonksiyon imzasının doğru olduğunu doğrulayın.</li><li><code>RIP</code>, <code>RSP</code>, <code>RCX</code>, <code>RDX</code> ile çağrı sonrası <code>RAX</code> değerini trace loglardan karşılaştırın.</li><li>Stack argümanı varsa dönüş zincirinin çağrıdan sonra geri yüklendiğini doğrulayın.</li><li>Hedef thread&#39;in exit code&#39;unu, suspend sayacını ve lock durumunu inceleyin.</li><li>Sorunu en küçük, hızlı dönen ve yan etkisiz fonksiyonla yeniden üretin.</li></ol><blockquote><p>Hedef süreç çöktüyse aynı thread/context ile devam etmeye çalışmayın. Yeni bir hedef örneği başlatıp adres ve ABI varsayımlarını önce orada doğrulayın.</p></blockquote>',16)])])}const y=e(l,[["render",d]]);export{k as __pageData,y as default};
